import React from 'react';
import { NavLink } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import './Sidebar.css';

const NAV_ITEMS = [
  { path: '/dashboard',  label: 'Dashboard',    icon: '📊', roles: ['admin', 'manager', 'employee'] },
  { path: '/attendance', label: 'Pontaj',        icon: '⏱',  roles: ['admin', 'manager', 'employee'] },
  { path: '/leaves',     label: 'Concedii',      icon: '🏖',  roles: ['admin', 'manager', 'employee'] },
  { path: '/salary',     label: 'Salarii',       icon: '💰', roles: ['admin', 'manager', 'employee'] },
  { path: '/employees',  label: 'Angajați',      icon: '👥', roles: ['admin', 'manager'] },
  { path: '/shifts',     label: 'Schimburi',     icon: '📅', roles: ['admin', 'manager'] },
  { path: '/reports',    label: 'Rapoarte',      icon: '📈', roles: ['admin', 'manager'] },
];

const Sidebar = ({ isOpen, onClose }) => {
  const { currentUser } = useAuth();

  return (
    <>
      {isOpen && <div className="sidebar-overlay" onClick={onClose} />}
      <aside className={`sidebar ${isOpen ? 'sidebar-open' : ''}`}>
        {/* Logo */}
        <div className="sidebar-logo">
          <span className="sidebar-logo-icon">⛓</span>
          <span className="sidebar-logo-text">Chain</span>
          <span className="sidebar-logo-sub">HR Management</span>
        </div>

        {/* Nav */}
        <nav className="sidebar-nav">
          {NAV_ITEMS.filter((i) => i.roles.includes(currentUser?.role)).map((item) => (
            <NavLink
              key={item.path}
              to={item.path}
              className={({ isActive }) => `sidebar-item ${isActive ? 'sidebar-item-active' : ''}`}
              onClick={onClose}
            >
              <span className="sidebar-item-icon">{item.icon}</span>
              <span className="sidebar-item-label">{item.label}</span>
            </NavLink>
          ))}
        </nav>

        {/* Profile */}
        <div className="sidebar-profile">
          <div className="sidebar-avatar">
            {currentUser?.firstName?.[0]}{currentUser?.lastName?.[0]}
          </div>
          <div className="sidebar-profile-info">
            <p className="sidebar-profile-name">{currentUser?.firstName} {currentUser?.lastName}</p>
            <p className="sidebar-profile-role">{currentUser?.role}</p>
          </div>
        </div>
      </aside>
    </>
  );
};

export default Sidebar;
